Connect-MgGraph -TenantId 'contoso-ext.onmicrosoft.com' `
    -Scopes 'Policy.ReadWrite.ConditionalAccess'

# Require MFA for all sign-ins from outside the corporate IP range
$caPolicy = @{
    displayName = 'CIAM - Require MFA outside corporate network'
    state       = 'enabled'
    conditions  = @{
        users = @{
            includeUsers = @('All')
        }
        applications = @{
            includeApplications = @('All')
        }
        locations = @{
            includeLocations = @('All')
            excludeLocations = @('<named-location-id-for-corporate-ip>')
        }
    }
    grantControls = @{
        operator         = 'OR'
        builtInControls  = @('mfa')
    }
}

New-MgIdentityConditionalAccessPolicy -BodyParameter $caPolicy
Write-Host 'Conditional Access policy created for External ID.'

Connect-MgGraph -TenantId 'contoso.onmicrosoft.com' -Scopes 'User.ReadWrite.All'

# Create a local account user in B2C
New-MgUser -BodyParameter @{
    DisplayName = 'Jane Consumer'
    Identities  = @(
        @{
            SignInType       = 'emailAddress'
            Issuer           = 'contoso.onmicrosoft.com'
            IssuerAssignedId = 'jane@example.com'
        }
    )
    PasswordProfile = @{
        Password                      = 'Temp@Pass123!'
        ForceChangePasswordNextSignIn = $true
    }
    PasswordPolicies = 'DisablePasswordExpiration'
}
Write-Host 'B2C local account user created.'

Connect-MgGraph -TenantId 'contoso-ext.onmicrosoft.com' -Scopes 'User.ReadWrite.All'

# User creation in External ID uses the same Graph API — identical shape
New-MgUser -BodyParameter @{
    DisplayName = 'Jane Consumer'
    Identities  = @(
        @{
            SignInType       = 'emailAddress'
            Issuer           = 'contoso-ext.onmicrosoft.com'
            IssuerAssignedId = 'jane@example.com'
        }
    )
    PasswordProfile = @{
        Password                      = 'Temp@Pass123!'
        ForceChangePasswordNextSignIn = $true
    }
    PasswordPolicies = 'DisablePasswordExpiration'
}
Write-Host 'External ID consumer user created.'
# Note: The API call is identical — authority and tenant context are the only difference.

# B2C: provider points to the B2C tenant
provider "azuread" {
  alias     = "b2c"
  tenant_id = var.b2c_tenant_id
}

# External ID: provider points to the External ID tenant
provider "azuread" {
  alias     = "external_id"
  tenant_id = var.external_id_tenant_id
}

# App registration in B2C
resource "azuread_application" "b2c_app" {
  provider     = azuread.b2c
  display_name = "ContosoApp-B2C"
  web {
    redirect_uris = ["https://app.contoso.com/signin-oidc"]
  }
}

# App registration in External ID — identical resource, different provider
resource "azuread_application" "ext_id_app" {
  provider     = azuread.external_id
  display_name = "ContosoApp-ExternalID"
  web {
    redirect_uris = ["https://app.contoso.com/signin-oidc"]
  }
}
